// User & Auth Types
export type UserRole = 'super_admin' | 'site_manager' | 'safety_officer' | 'supervisor';

export interface User {
  id: string;
  email: string;
  name: string;
  role: UserRole;
  organization?: Organization;
  sites?: Site[];
  isActive: boolean;
  twoFactorEnabled: boolean;
  createdAt: string;
}

export interface AuthResponse {
  user: User;
  token: string;
}

// Organization
export interface Organization {
  id: string;
  name: string;
  address?: string;
  contactEmail?: string;
  contactPhone?: string;
  createdAt: string;
}

// Site
export interface SiteSettings {
  ppeRequired: string[];
  alertCooldownMinutes: number;
}

export interface Site {
  id: string;
  name: string;
  organization?: Organization;
  address?: string;
  timezone: string;
  cameraCount: number;
  isActive: boolean;
  settings: SiteSettings;
  createdAt: string;
}

// Camera & Zone
export interface Point {
  x: number;
  y: number;
}

export interface Zone {
  id: string;
  name: string;
  polygon: Point[];
  type: 'restricted' | 'hazard' | 'safe';
  schedule?: {
    start: string;
    end: string;
  };
}

export type CameraStatus = 'online' | 'offline' | 'maintenance';

export interface Camera {
  id: string;
  site: Site;
  name: string;
  streamUrl?: string;
  location?: string;
  status: CameraStatus;
  zones: Zone[];
  lastSeen?: string;
  createdAt: string;
}

// Violation
export type ViolationType = 'ppe_violation' | 'zone_violation' | 'behavior' | 'fall' | 'fire';
export type ViolationSeverity = 'low' | 'medium' | 'high' | 'critical';
export type ViolationStatus = 'new' | 'acknowledged' | 'resolved';

export interface ViolationDetails {
  ppeMissing?: string[];
  zoneName?: string;
  behaviorType?: string;
  confidence: number;
}

export interface ViolationEvidence {
  imageUrl?: string;
  videoClipUrl?: string;
  timestamp: string;
}

export interface Violation {
  id: string;
  site: Site;
  camera: Camera;
  type: ViolationType;
  severity: ViolationSeverity;
  details: ViolationDetails;
  evidence: ViolationEvidence;
  acknowledged: boolean;
  acknowledgedBy?: User;
  acknowledgedAt?: string;
  status: ViolationStatus;
  createdAt: string;
}

// Alert
export type AlertType = 'in_app' | 'email' | 'sms';
export type AlertStatus = 'pending' | 'sent' | 'failed';

export interface Alert {
  id: string;
  violation: Violation;
  type: AlertType;
  recipient: User;
  status: AlertStatus;
  sentAt?: string;
  error?: string;
}

// Report
export type ReportType = 'daily' | 'weekly' | 'monthly';

export interface TopViolationType {
  type: string;
  count: number;
}

export interface ReportMetrics {
  totalViolations: number;
  ppeComplianceRate: number;
  zoneViolations: number;
  topViolationTypes: TopViolationType[];
}

export interface Report {
  id: string;
  site: Site;
  period: {
    start: string;
    end: string;
  };
  type: ReportType;
  metrics: ReportMetrics;
  generatedBy: User;
  createdAt: string;
}

// Dashboard
export interface DashboardStats {
  totalViolations: number;
  ppeComplianceRate: number;
  activeAlerts: number;
  onlineCameras: number;
  totalSites: number;
}

export interface TrendData {
  date: string;
  complianceRate: number;
  violations: number;
}

export interface HeatmapData {
  zone: string;
  violations: number;
}

