import { create } from 'zustand';
import { User } from '@/types';
import { currentUser as mockUser } from '@/lib/mockData';

interface AuthState {
  user: User | null;
  isAuthenticated: boolean;
  isLoading: boolean;
  error: string | null;

  // Actions
  login: (email: string, password: string) => Promise<void>;
  logout: () => void;
  checkAuth: () => Promise<void>;
}

export const useAuthStore = create<AuthState>((set) => ({
  user: null,
  isAuthenticated: false,
  isLoading: false,
  error: null,

  login: async (email: string, password: string) => {
    set({ isLoading: true, error: null });

    // Simulate API call
    await new Promise(resolve => setTimeout(resolve, 1000));

    // Mock login - in real app, this would call the API
    if (email && password) {
      set({ 
        user: mockUser, 
        isAuthenticated: true, 
        isLoading: false 
      });
    } else {
      set({ 
        error: 'Invalid credentials', 
        isLoading: false 
      });
    }
  },

  logout: () => {
    set({ 
      user: null, 
      isAuthenticated: false,
      error: null
    });
  },

  checkAuth: async () => {
    set({ isLoading: true });
    // Check for existing session
    await new Promise(resolve => setTimeout(resolve, 500));
    // For demo, start logged out
    set({ isLoading: false });
  }
}));

import { create } from 'zustand';
import { Site, Camera } from '@/types';
import { mockSites, mockCameras } from '@/lib/mockData';

interface SiteState {
  sites: Site[];
  cameras: Camera[];
  currentSite: Site | null;
  currentCamera: Camera | null;
  isLoading: boolean;
  error: string | null;

  fetchSites: () => Promise<void>;
  fetchCameras: (siteId?: string) => Promise<void>;
  setCurrentSite: (site: Site | null) => void;
  setCurrentCamera: (camera: Camera | null) => void;
  createSite: (data: Partial<Site>) => Promise<void>;
  updateSite: (id: string, data: Partial<Site>) => Promise<void>;
}

export const useSiteStore = create<SiteState>((set, get) => ({
  sites: [],
  cameras: [],
  currentSite: null,
  currentCamera: null,
  isLoading: false,
  error: null,

  fetchSites: async () => {
    set({ isLoading: true, error: null });
    await new Promise(resolve => setTimeout(resolve, 500));
    set({ 
      sites: mockSites, 
      isLoading: false 
    });
  },

  fetchCameras: async (siteId?: string) => {
    set({ isLoading: true, error: null });
    await new Promise(resolve => setTimeout(resolve, 300));

    let cameras = mockCameras;
    if (siteId) {
      cameras = mockCameras.filter(cam => cam.site.id === siteId);
    }

    set({ 
      cameras: cameras, 
      isLoading: false 
    });
  },

  setCurrentSite: (site) => {
    set({ currentSite: site });
  },

  setCurrentCamera: (camera) => {
    set({ currentCamera: camera });
  },

  createSite: async (data) => {
    set({ isLoading: true });
    await new Promise(resolve => setTimeout(resolve, 500));

    const newSite: Site = {
      id: `site-${Date.now()}`,
      name: data.name || 'New Site',
      organization: data.organization,
      address: data.address,
      timezone: 'Asia/Ho_Chi_Minh',
      cameraCount: 0,
      isActive: true,
      settings: data.settings || {
        ppeRequired: ['hard_hat', 'vest'],
        alertCooldownMinutes: 5
      },
      createdAt: new Date().toISOString()
    };

    set(state => ({
      sites: [...state.sites, newSite],
      isLoading: false
    }));
  },

  updateSite: async (id, data) => {
    set({ isLoading: true });
    await new Promise(resolve => setTimeout(resolve, 500));

    set(state => ({
      sites: state.sites.map(site => 
        site.id === id ? { ...site, ...data } : site
      ),
      isLoading: false
    }));
  }
}));

import { create } from 'zustand';
import { Violation, ViolationType, ViolationSeverity } from '@/types';
import { mockViolations } from '@/lib/mockData';

interface ViolationFilters {
  siteId?: string;
  cameraId?: string;
  type?: ViolationType;
  severity?: ViolationSeverity;
  status?: 'new' | 'acknowledged' | 'resolved';
  dateFrom?: string;
  dateTo?: string;
}

interface ViolationState {
  violations: Violation[];
  filters: ViolationFilters;
  isLoading: boolean;
  error: string | null;

  fetchViolations: (filters?: ViolationFilters) => Promise<void>;
  acknowledgeViolation: (id: string) => Promise<void>;
  setFilters: (filters: ViolationFilters) => void;
  clearFilters: () => void;
}

export const useViolationStore = create<ViolationState>((set, get) => ({
  violations: [],
  filters: {},
  isLoading: false,
  error: null,

  fetchViolations: async (filters) => {
    set({ isLoading: true, error: null });
    await new Promise(resolve => setTimeout(resolve, 500));

    let filtered = [...mockViolations];

    if (filters?.siteId) {
      filtered = filtered.filter(v => v.site.id === filters.siteId);
    }
    if (filters?.type) {
      filtered = filtered.filter(v => v.type === filters.type);
    }
    if (filters?.severity) {
      filtered = filtered.filter(v => v.severity === filters.severity);
    }
    if (filters?.status) {
      filtered = filtered.filter(v => v.status === filters.status);
    }

    set({ 
      violations: filtered, 
      isLoading: false,
      filters: filters || {}
    });
  },

  acknowledgeViolation: async (id) => {
    set({ isLoading: true });
    await new Promise(resolve => setTimeout(resolve, 300));

    set(state => ({
      violations: state.violations.map(v => 
        v.id === id ? { 
          ...v, 
          acknowledged: true, 
          status: 'acknowledged' as const,
          acknowledgedAt: new Date().toISOString()
        } : v
      ),
      isLoading: false
    }));
  },

  setFilters: (filters) => {
    set({ filters });
  },

  clearFilters: () => {
    set({ filters: {} });
  }
}));

import { create } from 'zustand';
import { Alert } from '@/types';
import { mockAlerts } from '@/lib/mockData';

interface AlertState {
  alerts: Alert[];
  unreadCount: number;
  isLoading: boolean;
  error: string | null;

  fetchAlerts: () => Promise<void>;
  acknowledgeAlert: (id: string) => Promise<void>;
  markAllAsRead: () => void;
}

export const useAlertStore = create<AlertState>((set, get) => ({
  alerts: [],
  unreadCount: 0,
  isLoading: false,
  error: null,

  fetchAlerts: async () => {
    set({ isLoading: true, error: null });
    await new Promise(resolve => setTimeout(resolve, 300));

    const unread = mockAlerts.filter(a => a.status === 'pending').length;

    set({ 
      alerts: mockAlerts, 
      unreadCount: unread,
      isLoading: false 
    });
  },

  acknowledgeAlert: async (id) => {
    set({ isLoading: true });
    await new Promise(resolve => setTimeout(resolve, 200));

    set(state => ({
      alerts: state.alerts.map(alert => 
        alert.id === id ? { 
          ...alert, 
          status: 'sent' as const,
          sentAt: new Date().toISOString()
        } : alert
      ),
      unreadCount: Math.max(0, state.unreadCount - 1),
      isLoading: false
    }));
  },

  markAllAsRead: () => {
    set(state => ({
      alerts: state.alerts.map(alert => ({
        ...alert,
        status: 'sent' as const,
        sentAt: alert.sentAt || new Date().toISOString()
      })),
      unreadCount: 0
    }));
  }
}));

import React from 'react';
import { clsx } from 'clsx';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  isLoading?: boolean;
}

export function Button({
  children,
  variant = 'primary',
  size = 'md',
  isLoading = false,
  className,
  disabled,
  ...props
}: ButtonProps) {
  return (
    <button
      className={clsx(
        'inline-flex items-center justify-center font-medium rounded-lg transition-colors',
        'focus:outline-none focus:ring-2 focus:ring-offset-2',
        'disabled:opacity-50 disabled:cursor-not-allowed',

        // Variants
        {
          'bg-blue-600 text-white hover:bg-blue-700 focus:ring-blue-500': variant === 'primary',
          'bg-gray-200 text-gray-900 hover:bg-gray-300 focus:ring-gray-500': variant === 'secondary',
          'bg-red-600 text-white hover:bg-red-700 focus:ring-red-500': variant === 'danger',
          'bg-transparent text-gray-700 hover:bg-gray-100 focus:ring-gray-500': variant === 'ghost',
        },

        // Sizes
        {
          'px-3 py-1.5 text-sm': size === 'sm',
          'px-4 py-2 text-base': size === 'md',
          'px-6 py-3 text-lg': size === 'lg',
        },

        className
      )}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading && (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
        </svg>
      )}
      {children}
    </button>
  );
}

import React from 'react';
