      render: (violation: Violation) => <ViolationTypeBadge type={violation.type} />
    },
    {
      key: 'site',
      header: 'Site',
      render: (violation: Violation) => (
        <span className="font-medium">{violation.site.name}</span>
      )
    },
    {
      key: 'camera',
      header: 'Camera',
      render: (violation: Violation) => violation.camera.name
    },
    {
      key: 'time',
      header: 'Time',
      render: (violation: Violation) => (
        <span className="text-gray-500">
          {formatDistanceToNow(new Date(violation.createdAt), { addSuffix: true })}
        </span>
      )
    },
    {
      key: 'status',
      header: 'Status',
      render: (violation: Violation) => <ViolationStatusBadge status={violation.status} />
    }
  ];

  return (
    <Table
      columns={columns}
      data={displayViolations}
      keyExtractor={(v) => v.id}
      onRowClick={onRowClick}
      isLoading={isLoading}
      emptyMessage="No violations found"
    />
  );
}

'use client';

import React from 'react';
import { formatDistanceToNow } from 'date-fns';
import { AlertTriangle, AlertCircle, Info, X } from 'lucide-react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Alert } from '@/types';

interface AlertFeedProps {
  alerts: Alert[];
  onAcknowledge?: (id: string) => void;
  onViewAll?: () => void;
}

export function AlertFeed({ alerts, onAcknowledge, onViewAll }: AlertFeedProps) {
  const getAlertIcon = (type: Alert['violation']['type']) => {
    switch (type) {
      case 'ppe_violation':
      case 'fall':
      case 'fire':
        return <AlertTriangle className="w-5 h-5 text-red-500" />;
      case 'zone_violation':
        return <AlertCircle className="w-5 h-5 text-amber-500" />;
      default:
        return <Info className="w-5 h-5 text-blue-500" />;
    }
  };

  const getAlertBorderColor = (type: Alert['violation']['type']) => {
    switch (type) {
      case 'ppe_violation':
      case 'fall':
      case 'fire':
        return 'border-l-red-500';
      case 'zone_violation':
        return 'border-l-amber-500';
      default:
        return 'border-l-blue-500';
    }
  };

  return (
    <Card>
      <CardHeader className="flex flex-row items-center justify-between">
        <CardTitle>Recent Alerts</CardTitle>
        {onViewAll && (
          <Button variant="ghost" size="sm" onClick={onViewAll}>
            View All
          </Button>
        )}
      </CardHeader>
      <CardContent>
        <div className="space-y-3">
          {alerts.slice(0, 5).map((alert) => (
            <div
              key={alert.id}
              className={`flex items-start gap-3 p-3 bg-gray-50 rounded-lg border-l-4 ${getAlertBorderColor(alert.violation.type)}`}
            >
              <div className="flex-shrink-0 mt-0.5">
                {getAlertIcon(alert.violation.type)}
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-gray-900">
                  {alert.violation.type.replace('_', ' ').replace(/\b\w/g, l => l.toUpperCase())}
                </p>
                <p className="text-xs text-gray-500 mt-0.5">
                  {alert.violation.site.name} - {alert.violation.camera.name}
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  {formatDistanceToNow(new Date(alert.createdAt), { addSuffix: true })}
                </p>
              </div>
              {alert.status === 'pending' && onAcknowledge && (
                <button
                  onClick={() => onAcknowledge(alert.id)}
                  className="flex-shrink-0 p-1 hover:bg-gray-200 rounded"
                  title="Acknowledge"
                >
                  <X className="w-4 h-4 text-gray-400" />
                </button>
              )}
            </div>
          ))}

          {alerts.length === 0 && (
            <p className="text-center text-gray-500 py-4">No active alerts</p>
          )}
        </div>
      </CardContent>
    </Card>
  );
}

export { KPICard } from './KPICard';
export { ComplianceChart } from './ComplianceChart';
export { ViolationTable } from './ViolationTable';
export { AlertFeed } from './AlertFeed';

