          <h2 className="text-3xl font-bold mb-4">
            AI-Powered Construction Safety Monitoring
          </h2>
          <p className="text-blue-100 text-lg mb-8">
            Real-time PPE detection, zone violation alerts, and compliance analytics to keep your construction site safe.
          </p>
          <div className="space-y-4">
            <FeatureItem icon="🎯" text="Real-time PPE Detection" />
            <FeatureItem icon="📍" text="Zone Violation Monitoring" />
            <FeatureItem icon="📊" text="Compliance Analytics" />
            <FeatureItem icon="🔔" text="Instant Alerts" />
          </div>
        </div>
      </div>
    </div>
  );
}

