'use client';

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { Filter, Download, RefreshCw } from 'lucide-react';
import { Card } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Badge } from '@/components/ui/Badge';
import { ViolationTable } from '@/components/dashboard';
import { useViolationStore } from '@/stores/violationStore';
import { mockViolations, mockSites } from '@/lib/mockData';
import { ViolationType, ViolationSeverity, ViolationStatus } from '@/types';

export default function ViolationsPage() {
  const router = useRouter();
  const { violations, filters, setFilters, clearFilters, fetchViolations } = useViolationStore();

  const [selectedType, setSelectedType] = useState<string>('');
  const [selectedSeverity, setSelectedSeverity] = useState<string>('');
  const [selectedStatus, setSelectedStatus] = useState<string>('');
  const [selectedSite, setSelectedSite] = useState<string>('');

  useEffect(() => {
    fetchViolations();
  }, [fetchViolations]);

  const handleFilter = () => {
    const newFilters: any = {};
    if (selectedType) newFilters.type = selectedType;
    if (selectedSeverity) newFilters.severity = selectedSeverity;
    if (selectedStatus) newFilters.status = selectedStatus;
    if (selectedSite) newFilters.siteId = selectedSite;
    setFilters(newFilters);
  };

  const displayViolations = violations.length > 0 ? violations : mockViolations;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Violations</h1>
          <p className="text-gray-500">Monitor and manage safety violations</p>
        </div>
        <div className="flex items-center gap-3">
          <Button variant="secondary" onClick={() => fetchViolations()}>
            <RefreshCw className="w-4 h-4 mr-2" />
            Refresh
          </Button>
          <Button variant="secondary">
            <Download className="w-4 h-4 mr-2" />
            Export
          </Button>
        </div>
      </div>

      {/* Filters */}
      <Card padding="md">
        <div className="flex flex-wrap items-center gap-4">
          <div className="flex items-center gap-2">
            <Filter className="w-4 h-4 text-gray-400" />
            <span className="text-sm font-medium text-gray-700">Filters:</span>
          </div>

          <select
            value={selectedSite}
            onChange={(e) => setSelectedSite(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="">All Sites</option>
            {mockSites.map((site) => (
              <option key={site.id} value={site.id}>{site.name}</option>
            ))}
          </select>

          <select
            value={selectedType}
            onChange={(e) => setSelectedType(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="">All Types</option>
            <option value="ppe_violation">PPE Violation</option>
            <option value="zone_violation">Zone Violation</option>
            <option value="behavior">Behavior</option>
            <option value="fall">Fall</option>
            <option value="fire">Fire/Smoke</option>
          </select>

          <select
            value={selectedSeverity}
            onChange={(e) => setSelectedSeverity(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="">All Severities</option>
            <option value="critical">Critical</option>
            <option value="high">High</option>
            <option value="medium">Medium</option>
            <option value="low">Low</option>
          </select>

          <select
            value={selectedStatus}
            onChange={(e) => setSelectedStatus(e.target.value)}
            className="px-3 py-2 border border-gray-300 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            <option value="">All Status</option>
            <option value="new">New</option>
            <option value="acknowledged">Acknowledged</option>
            <option value="resolved">Resolved</option>
          </select>

          <Button variant="secondary" size="sm" onClick={handleFilter}>
            Apply Filters
          </Button>
          <Button variant="ghost" size="sm" onClick={clearFilters}>
            Clear
          </Button>
        </div>
      </Card>

      {/* Stats Summary */}
      <div className="grid grid-cols-4 gap-4">
        <StatCard label="Total" value={displayViolations.length} />
        <StatCard label="New" value={displayViolations.filter(v => v.status === 'new').length} color="red" />
        <StatCard label="Acknowledged" value={displayViolations.filter(v => v.status === 'acknowledged').length} color="amber" />
        <StatCard label="Resolved" value={displayViolations.filter(v => v.status === 'resolved').length} color="green" />
      </div>

      {/* Violations Table */}
      <ViolationTable
        violations={displayViolations}
        onRowClick={(v) => router.push(`/dashboard/violations/${v.id}`)}
      />
    </div>
  );
}

function StatCard({ label, value, color = 'gray' }: { label: string; value: number; color?: string }) {
  const colors = {
    gray: 'bg-gray-100 text-gray-700',
    red: 'bg-red-100 text-red-700',
    amber: 'bg-amber-100 text-amber-700',
    green: 'bg-green-100 text-green-700',
  };

  return (
    <Card padding="sm">
      <p className="text-sm text-gray-500">{label}</p>
      <p className={`text-2xl font-bold ${colors[color as keyof typeof colors].split(' ')[1]}`}>{value}</p>
    </Card>
  );
}

'use client';

