'use client';

import React, { useEffect, useState } from 'react';
import { formatDistanceToNow } from 'date-fns';
import { Bell, AlertTriangle, AlertCircle, Info, Check, Filter, RefreshCw } from 'lucide-react';
import { Card } from '@/components/ui/Card';
import { Button } from '@/components/ui/Button';
import { Badge, SeverityBadge } from '@/components/ui/Badge';
import { useAlertStore } from '@/stores/alertStore';
import { mockAlerts } from '@/lib/mockData';

export default function AlertsPage() {
  const { alerts, unreadCount, fetchAlerts, acknowledgeAlert, markAllAsRead } = useAlertStore();
  const [filter, setFilter] = useState<'all' | 'pending' | 'acknowledged'>('all');

  useEffect(() => {
    fetchAlerts();
  }, [fetchAlerts]);

  const displayAlerts = alerts.length > 0 ? alerts : mockAlerts;
  const filteredAlerts = filter === 'all' 
    ? displayAlerts 
    : filter === 'pending' 
      ? displayAlerts.filter(a => a.status === 'pending')
      : displayAlerts.filter(a => a.status !== 'pending');

  const getAlertIcon = (type: string) => {
    switch (type) {
      case 'ppe_violation':
      case 'fall':
      case 'fire':
        return <AlertTriangle className="w-5 h-5 text-red-500" />;
      case 'zone_violation':
        return <AlertCircle className="w-5 h-5 text-amber-500" />;
      default:
        return <Info className="w-5 h-5 text-blue-500" />;
    }
  };

  const getAlertBorderColor = (type: string, status: string) => {
    if (status === 'pending') {
      switch (type) {
        case 'ppe_violation':
        case 'fall':
        case 'fire':
          return 'border-l-red-500';
        case 'zone_violation':
          return 'border-l-amber-500';
        default:
          return 'border-l-blue-500';
      }
    }
    return 'border-l-gray-300';
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Alerts</h1>
          <p className="text-gray-500">
            {unreadCount > 0 ? `${unreadCount} unread alerts requiring attention` : 'All alerts acknowledged'}
          </p>
        </div>
        <div className="flex items-center gap-3">
          {unreadCount > 0 && (
            <Button variant="secondary" onClick={markAllAsRead}>
              <Check className="w-4 h-4 mr-2" />
              Mark All as Read
            </Button>
          )}
          <Button variant="secondary" onClick={() => fetchAlerts()}>
            <RefreshCw className="w-4 h-4 mr-2" />
            Refresh
          </Button>
        </div>
      </div>

      {/* Filters */}
      <Card padding="md">
        <div className="flex items-center gap-4">
          <div className="flex items-center gap-2">
            <Filter className="w-4 h-4 text-gray-400" />
            <span className="text-sm font-medium text-gray-700">Filter:</span>
          </div>
          <div className="flex gap-2">
            <Button 
              variant={filter === 'all' ? 'primary' : 'ghost'} 
              size="sm"
              onClick={() => setFilter('all')}
            >
              All ({displayAlerts.length})
            </Button>
            <Button 
              variant={filter === 'pending' ? 'primary' : 'ghost'} 
              size="sm"
              onClick={() => setFilter('pending')}
            >
              Pending ({displayAlerts.filter(a => a.status === 'pending').length})
            </Button>
            <Button 
              variant={filter === 'acknowledged' ? 'primary' : 'ghost'} 
              size="sm"
              onClick={() => setFilter('acknowledged')}
            >
              Acknowledged ({displayAlerts.filter(a => a.status !== 'pending').length})
            </Button>
          </div>
        </div>
      </Card>

      {/* Alerts List */}
      <div className="space-y-3">
        {filteredAlerts.map((alert) => (
          <Card 
            key={alert.id} 
            padding="none"
            className={`border-l-4 ${getAlertBorderColor(alert.violation.type, alert.status)}`}
          >
            <div className="p-4">
              <div className="flex items-start gap-4">
                {/* Icon */}
                <div className="flex-shrink-0 mt-1">
                  {getAlertIcon(alert.violation.type)}
                </div>

                {/* Content */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-start justify-between">
                    <div>
                      <h3 className="font-semibold text-gray-900">
                        {alert.violation.type.replace('_', ' ').replace(/\b\w/g, l => l.toUpperCase())}
                      </h3>
                      <p className="text-sm text-gray-600 mt-1">
                        {alert.violation.site.name} - {alert.violation.camera.name}
                      </p>
                    </div>
                    <div className="flex items-center gap-2">
                      <SeverityBadge severity={alert.violation.severity} />
                      <Badge variant={alert.status === 'pending' ? 'danger' : 'success'}>
                        {alert.status === 'pending' ? 'Pending' : 'Acknowledged'}
                      </Badge>
                    </div>
                  </div>

                  {/* Details */}
                  <div className="mt-3 flex flex-wrap gap-4 text-sm text-gray-500">
                    {alert.violation.details.ppeMissing && (
                      <span>Missing: {alert.violation.details.ppeMissing.join(', ')}</span>
                    )}
                    {alert.violation.details.zoneName && (
                      <span>Zone: {alert.violation.details.zoneName}</span>
                    )}
                    <span>
                      {formatDistanceToNow(new Date(alert.createdAt), { addSuffix: true })}
                    </span>
                  </div>

                  {/* Actions */}
                  {alert.status === 'pending' && (
                    <div className="mt-4 flex gap-2">
                      <Button 
                        size="sm" 
                        onClick={() => acknowledgeAlert(alert.id)}
                      >
                        <Check className="w-4 h-4 mr-1" />
                        Acknowledge
                      </Button>
                      <Button variant="secondary" size="sm">
                        View Violation
                      </Button>
                      <Button variant="ghost" size="sm">
                        Dismiss
                      </Button>
                    </div>
                  )}
                </div>
              </div>
            </div>
          </Card>
        ))}

        {filteredAlerts.length === 0 && (
          <Card padding="lg" className="text-center">
            <Bell className="w-12 h-12 text-gray-300 mx-auto mb-4" />
            <p className="text-gray-500">No alerts to display</p>
          </Card>
        )}
      </div>
    </div>
  );
}

