import { User } from '../models/index.js';

export default async function authRoutes(fastify) {
  // Register
  fastify.post('/register', {
    schema: {
      body: {
        type: 'object',
        required: ['email', 'password', 'name'],
        properties: {
          email: { type: 'string', format: 'email' },
          password: { type: 'string', minLength: 6 },
          name: { type: 'string', minLength: 1 },
          role: { type: 'string', enum: ['super_admin', 'site_manager', 'safety_officer', 'supervisor'] },
        },
      },
    },
  }, async (request, reply) => {
    const { email, password, name, role } = request.body;

    const existingUser = await User.findOne({ email });
    if (existingUser) {
      return reply.status(400).send({ 
        error: 'Bad Request', 
        message: 'Email already registered' 
      });
    }

    const user = new User({ 
      email, 
      password, 
      name, 
      role: role || 'supervisor' 
    });
    await user.save();

    const token = fastify.jwt.sign({ 
      id: user._id, 
      email: user.email, 
      role: user.role 
    });

    return reply.status(201).send({ 
      user: user.toJSON(), 
      token 
    });
  });

  // Login
  fastify.post('/login', {
    schema: {
      body: {
        type: 'object',
        required: ['email', 'password'],
        properties: {
          email: { type: 'string', format: 'email' },
          password: { type: 'string' },
        },
      },
    },
  }, async (request, reply) => {
    const { email, password } = request.body;

    const user = await User.findOne({ email });
    if (!user) {
      return reply.status(401).send({ 
        error: 'Unauthorized', 
        message: 'Invalid email or password' 
      });
    }

    const isValid = await user.comparePassword(password);
    if (!isValid) {
      return reply.status(401).send({ 
        error: 'Unauthorized', 
        message: 'Invalid email or password' 
      });
    }

    if (!user.isActive) {
      return reply.status(403).send({ 
        error: 'Forbidden', 
        message: 'Account is deactivated' 
      });
    }

    const token = fastify.jwt.sign({ 
      id: user._id, 
      email: user.email, 
      role: user.role 
    });

    return { 
      user: user.toJSON(), 
      token 
    };
  });

  // Get current user
  fastify.get('/me', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const user = await User.findById(request.user.id)
      .populate('organization')
      .populate('sites');

    if (!user) {
      return reply.status(404).send({ 
        error: 'Not Found', 
        message: 'User not found' 
      });
    }

    return user.toJSON();
  });

  // Refresh token
  fastify.post('/refresh', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const token = fastify.jwt.sign({ 
      id: request.user.id, 
      email: request.user.email, 
      role: request.user.role 
    });

    return { token };
  });

  // Logout (client-side, just acknowledge)
  fastify.post('/logout', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    return { message: 'Logged out successfully' };
  });
}

import { User } from '../models/index.js';

export default async function userRoutes(fastify) {
  // List users (admin only)
  fastify.get('/', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const { page = 1, limit = 20, role, isActive } = request.query;

    const query = {};
    if (role) query.role = role;
    if (isActive !== undefined) query.isActive = isActive === 'true';

    const users = await User.find(query)
      .populate('organization')
      .populate('sites')
      .skip((page - 1) * limit)
      .limit(parseInt(limit))
      .sort({ createdAt: -1 });

    const total = await User.countDocuments(query);

    return {
      data: users.map(u => u.toJSON()),
      pagination: {
        page: parseInt(page),
        limit: parseInt(limit),
        total,
        pages: Math.ceil(total / limit),
      },
    };
  });

  // Get user by ID
  fastify.get('/:id', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const user = await User.findById(request.params.id)
      .populate('organization')
      .populate('sites');

    if (!user) {
      return reply.status(404).send({ 
        error: 'Not Found', 
        message: 'User not found' 
      });
    }

    return user.toJSON();
  });

  // Create user
  fastify.post('/', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const { email, password, name, role, organization, sites } = request.body;

    const existing = await User.findOne({ email });
    if (existing) {
      return reply.status(400).send({ 
        error: 'Bad Request', 
        message: 'Email already exists' 
      });
    }

    const user = new User({ 
      email, 
      password, 
      name, 
      role, 
      organization, 
      sites 
    });
    await user.save();

    return reply.status(201).send(user.toJSON());
  });

  // Update user
  fastify.patch('/:id', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const updates = request.body;

    // Prevent password updates via this route
    delete updates.password;
    delete updates.email; // Can't change email

    const user = await User.findByIdAndUpdate(
      request.params.id,
      updates,
      { new: true, runValidators: true }
    )
      .populate('organization')
      .populate('sites');

    if (!user) {
      return reply.status(404).send({ 
        error: 'Not Found', 
        message: 'User not found' 
      });
    }

    return user.toJSON();
  });

  // Delete user
  fastify.delete('/:id', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const user = await User.findByIdAndDelete(request.params.id);

    if (!user) {
      return reply.status(404).send({ 
        error: 'Not Found', 
        message: 'User not found' 
      });
    }

    return { message: 'User deleted successfully' };
  });
}

