    await site.save();

    return reply.status(201).send(site);
  });

  // Update site
  fastify.patch('/:id', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const site = await Site.findByIdAndUpdate(
      request.params.id,
      request.body,
      { new: true, runValidators: true }
    );

    if (!site) {
      return reply.status(404).send({ 
        error: 'Not Found', 
        message: 'Site not found' 
      });
    }

    return site;
  });

  // Delete site
  fastify.delete('/:id', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const site = await Site.findByIdAndDelete(request.params.id);

    if (!site) {
      return reply.status(404).send({ 
        error: 'Not Found', 
        message: 'Site not found' 
      });
    }

    return { message: 'Site deleted successfully' };
  });

  // Get site stats
  fastify.get('/:id/stats', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const siteId = request.params.id;

    const [site, cameras, violations] = await Promise.all([
      Site.findById(siteId),
      Camera.countDocuments({ site: siteId }),
      Violation.find({ site: siteId }).sort({ createdAt: -1 }).limit(100),
    ]);

    if (!site) {
      return reply.status(404).send({ 
        error: 'Not Found', 
        message: 'Site not found' 
      });
    }

    // Calculate stats
    const now = new Date();
    const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

    const weekViolations = violations.filter(v => new Date(v.createdAt) >= weekAgo);
    const newViolations = violations.filter(v => v.status === 'new');
    const acknowledgedViolations = violations.filter(v => v.status === 'acknowledged');
    const resolvedViolations = violations.filter(v => v.status === 'resolved');

    const complianceRate = violations.length > 0 
      ? (resolvedViolations.length / violations.length) 
      : 1;

    return {
      site: site,
      stats: {
        totalCameras: cameras,
        totalViolations: violations.length,
        weekViolations: weekViolations.length,
        newViolations: newViolations.length,
        acknowledgedViolations: acknowledgedViolations.length,
        resolvedViolations: resolvedViolations.length,
        complianceRate: Math.round(complianceRate * 100) / 100,
      },
    };
  });
}

