    await violation.save();

    // Create alerts for site managers and safety officers
    // This would be handled by the alert service
    const alert = new Alert({
      violation: violation._id,
      type: 'in_app',
      recipient: request.body.recipientId || request.user?.id,
      status: 'pending',
