        acknowledgedAt: new Date(),
        status: 'acknowledged',
      },
      { new: true }
    )
      .populate('site')
      .populate('camera')
      .populate('acknowledgedBy');

    if (!violation) {
      return reply.status(404).send({ 
        error: 'Not Found', 
        message: 'Violation not found' 
      });
    }

    return violation;
  });

