  fastify.patch('/:id/resolve', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const violation = await Violation.findByIdAndUpdate(
      request.params.id,
      {
        status: 'resolved',
      },
      { new: true }
    )
      .populate('site')
      .populate('camera');

    if (!violation) {
      return reply.status(404).send({ 
        error: 'Not Found', 
        message: 'Violation not found' 
      });
    }

    return violation;
  });

  // Get violation stats
