      total,
      byType,
      bySeverity,
      byStatus,
    };
  });
}

import { Site, Camera, Violation, Alert, User } from '../models/index.js';

export default async function dashboardRoutes(fastify) {
  // Overview stats
  fastify.get('/overview', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const { siteId } = request.query;

    const siteQuery = siteId ? { _id: siteId } : {};

    const [sites, cameras, violations, alerts, users] = await Promise.all([
      Site.countDocuments({ ...siteQuery, isActive: true }),
      siteId 
        ? Camera.countDocuments({ site: siteId }) 
        : Camera.countDocuments(),
      Violation.countDocuments(siteId ? { site: siteId } : {}),
      Alert.countDocuments({ status: 'pending' }),
      User.countDocuments({ isActive: true }),
    ]);

    // Get recent violations for compliance calculation
    const recentViolations = await Violation.find(
      siteId ? { site: siteId } : {}
    ).sort({ createdAt: -1 }).limit(100);

    const resolved = recentViolations.filter(v => v.status === 'resolved').length;
    const complianceRate = recentViolations.length > 0 
      ? Math.round((resolved / recentViolations.length) * 100) / 100 
      : 1;

    return {
      stats: {
        totalSites: sites,
        totalCameras: cameras,
        totalViolations: violations,
        activeAlerts: alerts,
        totalUsers: users,
        ppeComplianceRate: complianceRate,
      },
      onlineCameras: await Camera.countDocuments({ 
        status: 'online',
        ...(siteId ? { site: siteId } : {}),
      }),
    };
  });

  // Trends data
  fastify.get('/trends', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const { siteId, days = 7 } = request.query;

    const query = siteId ? { site: siteId } : {};
    const startDate = new Date();
    startDate.setDate(startDate.getDate() - parseInt(days));

    const violations = await Violation.find({
      ...query,
      createdAt: { $gte: startDate },
    }).sort({ createdAt: 1 });

    // Group by day
    const byDay = {};

    violations.forEach(v => {
      const date = new Date(v.createdAt).toISOString().split('T')[0];
      if (!byDay[date]) {
        byDay[date] = { violations: 0, complianceRate: 1 };
      }
      byDay[date].violations++;
    });

    // Calculate compliance rate per day
    const daysArray = Object.keys(byDay).sort();

    return daysArray.map(date => ({
      date,
      violations: byDay[date].violations,
      complianceRate: 1 - (byDay[date].violations / 50), // Simplified calculation
    }));
  });

  // Heatmap data
  fastify.get('/heatmap', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const { siteId } = request.query;

    const query = siteId ? { site: siteId } : {};
    const cameras = await Camera.find(query).populate('site');

    const heatmapData = await Promise.all(
      cameras.map(async (camera) => {
        const violations = await Violation.countDocuments({ 
          camera: camera._id,
          createdAt: { 
            $gte: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000) // Last 7 days
          },
        });

        return {
          cameraId: camera._id,
          cameraName: camera.name,
          siteName: camera.site?.name,
          location: camera.location,
          violations,
          severity: violations > 20 ? 'high' : violations > 10 ? 'medium' : 'low',
        };
      })
    );

    // Sort by violations descending
    heatmapData.sort((a, b) => b.violations - a.violations);

    return heatmapData;
  });

  // Recent activity
  fastify.get('/activity', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const { siteId, limit = 10 } = request.query;

    const query = siteId ? { site: siteId } : {};

    const recentViolations = await Violation.find(query)
      .populate('site')
      .populate('camera')
      .sort({ createdAt: -1 })
      .limit(parseInt(limit));

    const recentAlerts = await Alert.find()
      .populate({
        path: 'violation',
        populate: [
          { path: 'site' },
          { path: 'camera' },
        ],
      })
      .sort({ createdAt: -1 })
      .limit(parseInt(limit));

    return {
      violations: recentViolations,
      alerts: recentAlerts,
    };
  });
}

import { Alert, Violation } from '../models/index.js';

export default async function alertRoutes(fastify) {
  // List alerts
  fastify.get('/', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const { page = 1, limit = 20, status, type } = request.query;

    const query = {};
    if (status) query.status = status;
    if (type) query.type = type;

    // Only show alerts for current user or all if admin
    if (request.user.role !== 'super_admin' && request.user.role !== 'site_manager') {
      query.recipient = request.user.id;
    }

    const alerts = await Alert.find(query)
      .populate({
        path: 'violation',
        populate: [
          { path: 'site' },
          { path: 'camera' },
        ],
      })
      .populate('recipient')
      .skip((page - 1) * limit)
      .limit(parseInt(limit))
      .sort({ createdAt: -1 });

    const total = await Alert.countDocuments(query);

    // Count unread
    const unreadCount = await Alert.countDocuments({
      ...query,
      status: 'pending',
    });

    return {
      data: alerts,
      unreadCount,
      pagination: {
        page: parseInt(page),
        limit: parseInt(limit),
        total,
        pages: Math.ceil(total / limit),
      },
    };
  });

  // Get alert by ID
  fastify.get('/:id', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const alert = await Alert.findById(request.params.id)
      .populate({
        path: 'violation',
        populate: [
          { path: 'site' },
          { path: 'camera' },
        ],
      })
      .populate('recipient');

    if (!alert) {
      return reply.status(404).send({ 
        error: 'Not Found', 
        message: 'Alert not found' 
      });
    }

    return alert;
  });

  // Acknowledge alert
  fastify.patch('/:id/acknowledge', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const alert = await Alert.findByIdAndUpdate(
      request.params.id,
      {
        status: 'sent',
        sentAt: new Date(),
      },
      { new: true }
    )
      .populate({
        path: 'violation',
        populate: ['site', 'camera'],
      });

    if (!alert) {
      return reply.status(404).send({ 
        error: 'Not Found', 
        message: 'Alert not found' 
      });
    }

    // Also update the violation
    if (alert.violation) {
      await Violation.findByIdAndUpdate(alert.violation._id, {
        acknowledged: true,
        acknowledgedBy: request.user.id,
        acknowledgedAt: new Date(),
        status: 'acknowledged',
      });
    }

    return alert;
  });

  // Mark all as read
  fastify.post('/mark-all-read', {
    onRequest: [fastify.authenticate],
  }, async (request, reply) => {
    const result = await Alert.updateMany(
      { 
        status: 'pending',
        recipient: request.user.id,
      },
      {
        status: 'sent',
        sentAt: new Date(),
      }
    );

    return {
      message: 'All alerts marked as read',
      modifiedCount: result.modifiedCount,
    };
  });
}

import Fastify from 'fastify';
import cors from '@fastify/cors';
import { config } from './config/index.js';
import mongodbPlugin from './plugins/mongodb.js';
import authPlugin from './plugins/auth.js';

// Routes
import authRoutes from './routes/auth.js';
import userRoutes from './routes/users.js';
import siteRoutes from './routes/sites.js';
import cameraRoutes from './routes/cameras.js';
import violationRoutes from './routes/violations.js';
import alertRoutes from './routes/alerts.js';
import dashboardRoutes from './routes/dashboard.js';

const fastify = Fastify({
  logger: {
    level: 'info',
    transport: {
      target: 'pino-pretty',
      options: {
        translateTime: 'HH:MM:ss Z',
        ignore: 'pid,hostname',
      },
    },
  },
});

// Register plugins
await fastify.register(cors, {
  origin: config.corsOrigin,
  credentials: true,
});

await fastify.register(mongodbPlugin);
await fastify.register(authPlugin);

// Health check
fastify.get('/health', async () => {
  return { 
    status: 'ok', 
    timestamp: new Date().toISOString(),
    uptime: process.uptime(),
  };
});

// Register routes
await fastify.register(authRoutes, { prefix: '/api/auth' });
await fastify.register(userRoutes, { prefix: '/api/users' });
await fastify.register(siteRoutes, { prefix: '/api/sites' });
await fastify.register(cameraRoutes, { prefix: '/api/cameras' });
await fastify.register(violationRoutes, { prefix: '/api/violations' });
await fastify.register(alertRoutes, { prefix: '/api/alerts' });
await fastify.register(dashboardRoutes, { prefix: '/api/dashboard' });

// Global error handler
fastify.setErrorHandler((error, request, reply) => {
  fastify.log.error(error);

  const statusCode = error.statusCode || 500;
  const message = error.message || 'Internal Server Error';

  reply.status(statusCode).send({
    error: statusCode >= 500 ? 'Internal Server Error' : error.name || 'Error',
    message,
    statusCode,
  });
});

// Start server
const start = async () => {
  try {
    await fastify.listen({ 
      port: config.port, 
      host: config.host 
    });
    fastify.log.info(`Server running at http://${config.host}:${config.port}`);
  } catch (err) {
    fastify.log.error(err);
    process.exit(1);
  }
};

start();

